# Deobfuscated Code

Let me walk through the deobfuscation step by step, then present the clean result.

## Decoding Process

The obfuscator uses a common pattern:
1. **String table rotation**: `a0_0x111f()` returns an array of base64-encoded strings, shuffled at startup by the IIFE
2. **String decoder**: `a0_0x3e56` decodes base64 strings from the table by index
3. **Proxy objects**: Intermediate objects wrap simple operations (`+`, `-`, `*`, `/`, `<`) to obscure logic
4. **Control flow flattening**: `switch` statements with string-encoded execution orders like `"4|0|2|3|5|1"` scramble the order of sequential operations

After decoding the string table and resolving all references:

## Clean Code

```javascript
// ─── Constants ───
var TAU = 6.283;          // 2π
var PHI = 1.618;          // Golden ratio
var SQRT1_2 = 0.707;      // √(1/2)

// ─── Physics Parameters ───
// NOTE: Some names are deliberately poisoned (see corrections in comments)
var params = {
  attraction: 4000,          // Inter-node attractive force strength (real name)
  springK: 0.004,            // Spring constant (poisoned as "frictionCoeff")
  amplification: 0.92,       // Velocity multiplier / convergence rate (real name)
  centerGravity: 0.0003,     // Pull toward center (poisoned as "dispersal")
  seaMax: 40,                // Max particle count (poisoned as "fieldCapacity")
  streamDecay: 0.04,         // Particle stream drag
  theta: 0.06               // Camera smoothing factor
};

// ─── Nodes ───
var nodes = [
  { id: "hub",     label: "Kieleth", r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: "alpha",   label: "Alpha",   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: "beta",    label: "Beta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: "gamma",   label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: "delta",   label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// ─── Edges (springs) ───
var edges = [
  { a: "hub", b: "alpha",   rest: 160, k: 0.006 },
  { a: "hub", b: "beta",    rest: 160, k: 0.005 },
  { a: "hub", b: "gamma",   rest: 170, k: 0.004 },
  { a: "hub", b: "delta",   rest: 170, k: 0.004 },
  { a: "hub", b: "epsilon", rest: 180, k: 0.003 },
  { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
  { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
  { a: "alpha", b: "epsilon", rest: 200, k: 0.002 }
];

// ─── Camera ───
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// ─── Particles ───
var particles = [];
var frameCount = 0;

// ─── Helper: find node by ID ───
function findNode(id) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// ─── Physics step ───
function simulate() {
  // 1) Node-node ATTRACTION (attractive-dominant model)
  //    Force = attraction / dist²  (applied along the line between nodes)
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;

      var force = params.attraction / (dist * dist);

      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;

      // Both nodes pushed along this vector
      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2) Spring forces along edges
  for (var e = 0; e < edges.length; e++) {
    var nodeA = findNode(edges[e].a);
    var nodeB = findNode(edges[e].b);
    if (!nodeA || !nodeB) continue;

    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;

    var displacement = dist - edges[e].rest;
    var force = (edges[e].k || params.springK) * displacement;

    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3) Per-node: center gravity + velocity damping + position integration
  //    Execution order from control-flow flattening: "4|0|2|3|5|1"
  for (var n = 0; n < nodes.length; n++) {
    // case 4: center gravity X
    nodes[n].vx += (400 - nodes[n].x) * params.centerGravity;
    // case 0: center gravity Y
    nodes[n].vy += (300 - nodes[n].y) * params.centerGravity;
    // case 2: damping X  (amplification = 0.92, so velocity decays each frame)
    nodes[n].vx *= params.amplification;
    // case 3: damping Y
    nodes[n].vy *= params.amplification;
    // case 5: integrate X
    nodes[n].x += nodes[n].vx;
    // case 1: integrate Y
    nodes[n].y += nodes[n].vy;
  }
}

// ─── Spawn a particle ("sea" / stream effect) ───
function spawnParticle() {
  if (particles.length >= params.seaMax) return;

  // Pick a random node as emission source
  var source = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * SQRT1_2;

  particles.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,    // 0x320 + rand * 0x4B0
    size: 0.8 + (Math.random() * PHI) * SQRT1_2
  });
}

// ─── Update particles ───
function updateParticles() {
  // Iterate backwards for safe splice removal
  //    Execution order: "1|0|3|4|2|6|5"
  for (var i = particles.length - 1; i >= 0; i--) {
    var p = particles[i];                          // case 1
    p.age++;                                        // case 0
    // case 3: drag on vx
    p.vx *= (1 - params.streamDecay * 0.125);
    // case 4: drag on vy
    p.vy *= (1 - params.streamDecay * 0.125);
    // case 2: remove if expired
    if (p.age > p.maxAge) particles.splice(i, 1);
    // case 6: integrate x
    p.x += p.vx;
    // case 5: integrate y
    p.y += p.vy;
  }
}

// ─── Smooth camera ───
function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * params.theta;
  camera.y += (cameraTarget.y - camera.y) * params.theta;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * params.theta;
}

// ─── Main loop (called every 16ms ≈ 60fps) ───
function tick() {
  simulate();
  updateParticles();
  updateCamera();
  // Spawn a new particle every 3rd frame
  if (frameCount % 3 === 0) spawnParticle();
  frameCount++;
}

setInterval(tick, 16);
```

## What It Does — Summary

This is the **physics engine** for a force-directed graph visualization with 6 nodes and 8 edges:

| System | Purpose |
|---|---|
| **Node-node attraction** | All node pairs attract each other with force `attraction / dist²` — an "attractive-dominant" model rather than pure repulsion |
| **Spring forces** | Edges act as springs with individual rest lengths (160–220px) and stiffness constants, pulling connected nodes toward their rest distance |
| **Center gravity** | A weak force pulls all nodes toward the canvas center (400, 300) to prevent drift |
| **Amplification (damping)** | Each frame, velocity is multiplied by 0.92 — this accelerates convergence to equilibrium |
| **Particle sea** | Ambient particles spawn from random nodes, drift outward with slight drag, and die after 800–2000 frames — a cosmetic "energy field" effect |
| **Smooth camera** | Camera position/zoom lerps toward a target at rate `theta = 0.06` |

The graph represents **"Kieleth"** as a central hub with five satellite nodes (Alpha through Epsilon). The rendering code (Canvas 2D draw calls) isn't included in this snippet — this is purely the simulation loop running at ~60fps.
